import java.util.*;

public class Solution {
    public static long solve(long n, long[][] edges) {
        // Build adjacency list
        List<List<long[]>> adj = new ArrayList<>();
        for (long i = 0; i < n; i++) {
            adj.add(new ArrayList<>());
        }
        for (long[] edge : edges) {
            long u = (long) edge[0];
            long v = (long) edge[1];
            long start = edge[2];
            long end = edge[3];
            adj.get((int) u).add(new long[] {v, start, end});
        }

        // Dijkstra's algorithm with priority queue
        PriorityQueue<long[]> pq = new PriorityQueue<>((a, b) -> Long.compare(a[0], b[0]));
        pq.offer(new long[] {0, 0}); // time, node

        // Array to track the minimum time to reach each node
        long[] minTime = new long[(int) n];
        Arrays.fill(minTime, Long.MAX_VALUE);
        minTime[0] = 0;

        while (!pq.isEmpty()) {
            long currentTime = pq.peek()[1];
            long node = pq.peek()[0];
            pq.poll();

            // If we already found a better time for this node, skip
            if (currentTime > minTime[node]) {
                continue;
            }

            // Try to move along each outgoing edge
            for (long[] edge : adj.get(node)) {
                long dest = edge[0];
                long edgeStart = edge[1];
                long edgeEnd = edge[2];

                // Check if we can use this edge at the current time
                if (edgeStart <= currentTime && currentTime <= edgeEnd) {
                    // We can take this edge, move to the destination node
                    long newTime = currentTime + 1;
                    if (newTime < minTime[dest]) {
                        minTime[dest] = newTime;
                        pq.offer(new long[] {dest, newTime});
                    }
                }
            }

            // Also consider staying at the current node
            if (currentTime < minTime[node]) {
                minTime[node] = currentTime;
                pq.offer(new long[] {node, currentTime});
            }
        }

        return minTime[(int) (n - 1)] == Long.MAX_VALUE ? -1 : minTime[(int) (n - 1)];
    }
}
